/**
 * MedX label forms runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Label association and required indicators.
 */
const LABEL_TOKENS = Object.freeze({
  primary: { value: "forms-label-primary", scope: "forms" },
  secondary: { value: "forms-label-secondary", scope: "forms" },
  muted: { value: "forms-label-muted", scope: "forms" },
  accent: { value: "forms-label-accent", scope: "forms" },
  surface: { value: "forms-label-surface", scope: "forms" },
});

const LABEL_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const LABEL_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const labelRegistry = new Map();
const LABEL_listeners = new Set();
let LABEL_seq = 0;

function createLabelId(prefix = "medx-forms-label") {
  LABEL_seq += 1;
  return `${prefix}-${LABEL_seq}`;
}

function registerLabel(config = {}) {
  const entryId = config.id ?? createLabelId();
  const preset = LABEL_PRESETS[config.preset ?? "default"] ?? LABEL_PRESETS.default;
  const token = LABEL_TOKENS[config.token ?? preset.token] ?? LABEL_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: LABEL_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  labelRegistry.set(entryId, entry);
  notifyLabelListeners("register", entry);
  return entry;
}

function updateLabel(id, patch = {}) {
  const entry = labelRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyLabelListeners("update", entry);
  return entry;
}

function resolveLabel(id) {
  const entry = labelRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listLabelEntries(filter = {}) {
  let items = Array.from(labelRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onLabelEvent(listener) {
  LABEL_listeners.add(listener);
  return () => LABEL_listeners.delete(listener);
}

function notifyLabelListeners(type, entry) {
  for (const listener of LABEL_listeners) {
    try {
      listener({ type, entry, registrySize: labelRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:forms:label] listener error", err.message);
    }
  }
}

function getLabelMetrics() {
  const items = listLabelEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(LABEL_TOKENS).length,
    presets: Object.keys(LABEL_PRESETS).length,
  };
}

async function runMedxLabel() {
  console.log("[medx:ui:forms:label] runtime initialized");
  console.log(`[medx:ui:forms:label] tokens=${Object.keys(LABEL_TOKENS).length} presets=${Object.keys(LABEL_PRESETS).length}`);

  const events = [];
  onLabelEvent((e) => events.push(e.type));

  const domains = Object.keys(LABEL_SUPPLY_CHAIN);
  const presets = Object.keys(LABEL_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerLabel({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "forms/label" },
    });
  }

  const first = listLabelEntries()[0];
  if (first) updateLabel(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getLabelMetrics();
  const resolved = first ? resolveLabel(first.id) : null;

  console.log(`[medx:ui:forms:label] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:forms:label] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:forms:label] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:forms:label] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:forms:label] bootstrap complete");
}

module.exports = runMedxLabel;
